1	const countNeighbors = (cell: number[], livingCells: number[][]): number => {
2	  const [x, y] = cell;
3	  return livingCells.filter(
4	    ([cx, cy]) =>
5	      Math.abs(cx - x) <= 1 &&
6	      Math.abs(cy - y) <= 1 &&
7	      !(cx === x && cy === y)
8	  ).length;
9	};
10	
11	const isAlive = (cell: number[], livingCells: number[][]): boolean =>
12	  livingCells.some(([cx, cy]) => cx === cell[0] && cy === cell[1]);
13	
14	const getDeadNeighbors = (livingCells: number[][]): number[][] => {
15	  const candidates: number[][] = [];
16	  for (const [x, y] of livingCells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const candidate = [x + dx, y + dy];
21	        if (!isAlive(candidate, livingCells) && !isAlive(candidate, candidates)) {
22	          candidates.push(candidate);
23	        }
24	      }
25	    }
26	  }
27	  return candidates;
28	};
29	
30	export const nextGeneration = (livingCells: number[][]): number[][] => {
31	  const survivors = livingCells.filter((cell) => {
32	    const neighborCount = countNeighbors(cell, livingCells);
33	    return neighborCount === 2 || neighborCount === 3;
34	  });
35	
36	  const newborns = getDeadNeighbors(livingCells).filter(
37	    (cell) => countNeighbors(cell, livingCells) === 3
38	  );
39	
40	  return [...survivors, ...newborns].sort(([ax, ay], [bx, by]) =>
41	    ay !== by ? ay - by : ax - bx
42	  );
43	};
